/* ── ADMIN ANALYTICS ── */
function AdminAnalytics({students,teachers}){
  const neet=students.filter(s=>s.subject==="NEET").length;
  const jee=students.filter(s=>s.subject==="JEE").length;
  const foundation=students.filter(s=>s.subject==="Foundation").length;
  const active=students.filter(s=>s.status!=="inactive").length;
  const inactive=students.filter(s=>s.status==="inactive").length;

  const streams=[
    {label:"NEET",count:neet,pct:students.length?Math.round(neet/students.length*100):0,color:"var(--green)"},
    {label:"JEE",count:jee,pct:students.length?Math.round(jee/students.length*100):0,color:"#1565c0"},
    {label:"Foundation",count:foundation,pct:students.length?Math.round(foundation/students.length*100):0,color:"#e65100"},
  ];

  return(
    <div>
      <div className="stat-grid">
        {[
          {v:students.length,l:"Total Students",c:"var(--green)"},
          {v:teachers.length,l:"Total Teachers",c:"#1565c0"},
          {v:active,l:"Active Students",c:"var(--green2)"},
          {v:inactive,l:"Inactive",c:"#c62828"},
        ].map((s,i)=>(
          <div key={i} className="stat-card">
            <div className="stat-stripe" style={{background:s.c}}/>
            <div className="stat-val" style={{color:s.c}}>{s.v}</div>
            <div className="stat-lbl">{s.l}</div>
          </div>
        ))}
      </div>

      <div className="g2">
        <div className="card">
          <div className="card-title">📊 Stream Distribution</div>
          {streams.map((s,i)=>(
            <div key={i} style={{marginBottom:"1rem"}}>
              <div className="btwn mb1">
                <span style={{fontWeight:700,fontSize:".84rem"}}>{s.label}</span>
                <span className="mono ts" style={{color:s.color,fontWeight:800}}>{s.count} ({s.pct}%)</span>
              </div>
              <div className="pb" style={{height:10}}>
                <div className="pf" style={{width:`${s.pct}%`,background:s.color}}/>
              </div>
            </div>
          ))}
        </div>

        <div className="card">
          <div className="card-title">👥 Students by Stream</div>
          {streams.map((s,i)=>(
            <div key={i} className="card-sm btwn mb2">
              <span style={{fontWeight:700,color:s.color}}>{s.label}</span>
              <span className="mono" style={{fontWeight:900,color:s.color,fontSize:"1.2rem"}}>{s.count}</span>
            </div>
          ))}
          <div className="div"/>
          <div className="btwn">
            <span style={{fontWeight:700}}>Total</span>
            <span className="mono" style={{fontWeight:900,color:"var(--green)",fontSize:"1.2rem"}}>{students.length}</span>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-title">👨‍🏫 Teacher Overview</div>
        <div className="tw"><table>
          <thead><tr><th>Name</th><th>Email</th><th>Subject</th><th>Phone</th><th>Status</th></tr></thead>
          <tbody>{teachers.map(t=>(
            <tr key={t.id}>
              <td style={{fontWeight:700}}>{t.name}</td>
              <td className="ts tm">{t.email}</td>
              <td><span className="chip">{t.subject}</span></td>
              <td className="ts tm mono">{t.phone||"—"}</td>
              <td><span className={`badge ${t.status==="active"?"bg":"br"}`}>{t.status}</span></td>
            </tr>
          ))}</tbody>
        </table></div>
      </div>

      <div className="card">
        <div className="card-title">👥 Full Student List</div>
        <div className="tw"><table>
          <thead><tr><th>#</th><th>Name</th><th>Roll No</th><th>Stream</th><th>Phone</th><th>Status</th></tr></thead>
          <tbody>{students.map((s,i)=>(
            <tr key={s.id}>
              <td className="ts tm">{i+1}</td>
              <td style={{fontWeight:700}}>{s.name}</td>
              <td><span className="chip mono">{s.rollNo}</span></td>
              <td><span className={`badge ${s.subject==="NEET"?"bg":"bc"}`}>{s.subject}</span></td>
              <td className="ts tm mono">{s.phone||"—"}</td>
              <td><span className={`badge ${s.status==="inactive"?"br":"bg"}`}>{s.status||"active"}</span></td>
            </tr>
          ))}</tbody>
        </table></div>
      </div>
    </div>
  );
}

/* ── NOTICE BOARD ── */
function NoticeBoard({announcements,setAnnouncements}){
  const [modal,setModal]=useState(false);
  const [form,setForm]=useState({title:"",body:"",target:"all",priority:"normal",date:new Date().toISOString().slice(0,10)});

  function add(){
    setAnnouncements(p=>[{id:`a_${Date.now()}`,...form},...p]);
    setModal(false);setForm({title:"",body:"",target:"all",priority:"normal",date:new Date().toISOString().slice(0,10)});
  }
  function del(id){if(window.confirm("Delete this notice?"))setAnnouncements(p=>p.filter(a=>a.id!==id));}

  return(
    <div>
      <div className="sh">
        <div className="st">Announcements ({announcements.length})</div>
        <button className="btn btn-primary" onClick={()=>setModal(true)}>+ New Notice</button>
      </div>
      {!announcements.length&&<div className="empty"><div style={{fontSize:"2.5rem",marginBottom:".7rem"}}>📢</div>No announcements yet.</div>}
      {announcements.map(a=>(
        <div key={a.id} className="card">
          <div className="btwn mb2">
            <div className="row">
              <span className={`badge ${a.priority==="high"?"br":"bg"}`}>{a.priority==="high"?"🔴 Urgent":"🟢 Normal"}</span>
              <span className="chip ts">{a.target==="all"?"👥 All":"📌 "+a.target}</span>
              <span className="ts tm">{a.date}</span>
            </div>
            <button className="btn btn-rose btn-sm" onClick={()=>del(a.id)}>🗑</button>
          </div>
          <div style={{fontWeight:800,marginBottom:".4rem"}}>{a.title}</div>
          <div className="ts tm">{a.body}</div>
        </div>
      ))}

      {modal&&(
        <div className="ov" onClick={()=>setModal(false)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-title">📢 New Announcement</div>
            <div className="fg"><label className="fl">Title</label>
              <input className="fi" placeholder="Announcement title" value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))}/></div>
            <div className="fg"><label className="fl">Message</label>
              <textarea className="fi" placeholder="Full announcement text…" value={form.body} onChange={e=>setForm(p=>({...p,body:e.target.value}))}/></div>
            <div className="g2">
              <div className="fg"><label className="fl">Target Audience</label>
                <select className="fi" value={form.target} onChange={e=>setForm(p=>({...p,target:e.target.value}))}>
                  <option value="all">All (Students + Teachers)</option>
                  <option value="students">Students Only</option>
                  <option value="teachers">Teachers Only</option>
                  <option value="neet">NEET Students</option>
                  <option value="jee">JEE Students</option>
                </select></div>
              <div className="fg"><label className="fl">Priority</label>
                <select className="fi" value={form.priority} onChange={e=>setForm(p=>({...p,priority:e.target.value}))}>
                  <option value="normal">Normal</option>
                  <option value="high">Urgent / High</option>
                </select></div>
            </div>
            <div className="fg"><label className="fl">Date</label>
              <input className="fi" type="date" value={form.date} onChange={e=>setForm(p=>({...p,date:e.target.value}))}/></div>
            <div className="row">
              <button className="btn btn-primary" onClick={add} disabled={!form.title||!form.body}>Post Notice</button>
              <button className="btn btn-ghost" onClick={()=>setModal(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ── BACKUP & RESTORE ── */
function BackupRestore({students,teachers,settings,announcements,onRestore}){
  const [status,setStatus]=useState("");
  const [restoreText,setRestoreText]=useState("");

  async function saveCloud(){
    setStatus("saving");
    try{
      const data={students,teachers,settings,announcements,version:"1.0",savedAt:new Date().toISOString()};
      await window.storage.set("thulir:admin",JSON.stringify(data));
      setStatus("✅ Backed up to cloud storage!");
    }catch(e){setStatus("❌ Cloud backup failed.");}
  }

  async function loadCloud(){
    setStatus("loading");
    try{
      const r=await window.storage.get("thulir:admin");
      if(r){const d=JSON.parse(r.value);onRestore(d);setStatus(`✅ Restored! Saved on ${d.savedAt?.slice(0,10)||"unknown date"}`);}
      else setStatus("⚠️ No cloud backup found.");
    }catch(e){setStatus("❌ Restore failed.");}
  }

  function downloadBackup(){
    const data={students,teachers,settings,announcements,version:"1.0",exportedAt:new Date().toISOString()};
    const blob=new Blob([JSON.stringify(data,null,2)],{type:"application/json"});
    const a=document.createElement("a");a.href=URL.createObjectURL(blob);
    a.download=`thulir_backup_${new Date().toISOString().slice(0,10)}.json`;a.click();
    setStatus("✅ Backup file downloaded!");
  }

  function restoreFromText(){
    try{
      const data=JSON.parse(restoreText);
      onRestore(data);
      setStatus(`✅ Restored from file! Students: ${data.students?.length||0}, Teachers: ${data.teachers?.length||0}`);
      setRestoreText("");
    }catch(e){setStatus("❌ Invalid JSON. Please paste a valid backup file.");}
  }

  const summary={students:students.length,teachers:teachers.length,announcements:announcements.length,date:new Date().toLocaleDateString()};

  return(
    <div>
      <div className="card" style={{background:"linear-gradient(135deg,var(--greenlt),#fff)",border:"1.5px solid var(--b2)"}}>
        <div className="card-title">📦 Current Data Snapshot</div>
        <div className="g2">
          {[{l:"Students",v:summary.students,icon:"👥"},{l:"Teachers",v:summary.teachers,icon:"👨‍🏫"},
            {l:"Notices",v:summary.announcements,icon:"📢"},{l:"Today",v:summary.date,icon:"📅"}].map((s,i)=>(
            <div key={i} className="card-sm" style={{textAlign:"center"}}>
              <div style={{fontSize:"1.4rem",marginBottom:".25rem"}}>{s.icon}</div>
              <div className="mono" style={{fontSize:"1.2rem",fontWeight:900,color:"var(--green)"}}>{s.v}</div>
              <div className="tx tm">{s.l}</div>
            </div>
          ))}
        </div>
      </div>

      {status&&<div style={{padding:".75rem",borderRadius:12,marginBottom:"1rem",fontSize:".82rem",fontWeight:700,
        background:status.startsWith("✅")?"var(--greenlt)":status.startsWith("❌")?"#ffebee":"#fff8e1",
        color:status.startsWith("✅")?"var(--green)":status.startsWith("❌")?"#c62828":"#e65100"}}>{status}</div>}

      <div className="g2">
        <div className="card">
          <div className="card-title">☁️ Cloud Backup</div>
          <p className="ts tm mb2">Save and restore data within this browser session.</p>
          <div className="row">
            <button className="btn btn-primary" onClick={saveCloud}>☁️ Save to Cloud</button>
            <button className="btn btn-ghost" onClick={loadCloud}>📂 Restore from Cloud</button>
          </div>
        </div>
        <div className="card">
          <div className="card-title">💾 File Backup</div>
          <p className="ts tm mb2">Download a full JSON backup file to your device.</p>
          <button className="btn btn-primary" onClick={downloadBackup}>⬇ Download Backup .json</button>
        </div>
      </div>

      <div className="card">
        <div className="card-title">📤 Restore from File</div>
        <p className="ts tm mb2">Paste the contents of a backup JSON file below to restore all data.</p>
        <textarea className="fi" style={{minHeight:110,fontFamily:"var(--mono)",fontSize:".73rem"}}
          placeholder='Paste backup JSON here: {"students":[...],"teachers":[...],...}'
          value={restoreText} onChange={e=>setRestoreText(e.target.value)}/>
        <button className="btn btn-primary" style={{marginTop:".75rem"}} onClick={restoreFromText} disabled={!restoreText.trim()}>
          📤 Restore from Pasted JSON
        </button>
      </div>
    </div>
  );
}

/* ── ROOT ── */
export default function App(){
  const [portal,setPortal]=useState(null);
  const [user,setUser]=useState(null);
  function logout(){setPortal(null);setUser(null);}
  return(
    <>
      <style>{CSS}</style>
      {!portal&&<Splash onSelect={setPortal}/>}
      {portal&&!user&&<Login role={portal} onLogin={setUser} onBack={()=>setPortal(null)}/>}
      {portal==="teacher"&&user&&<TeacherPortal user={user} onLogout={logout}/>}
      {portal==="student"&&user&&<StudentPortal user={user} onLogout={logout}/>}
      {portal==="admin"&&user&&<AdminPortal user={user} onLogout={logout}/>}
    </>
  );
}